const raw = $input.first().json;
let text = '';
if (raw.content && raw.content.parts) {
  text = raw.content.parts[0].text;
} else if (typeof raw === 'string') {
  text = raw;
} else if (raw.text) {
  text = raw.text;
} else {
  text = JSON.stringify(raw);
}

function cleanGeminiJson(raw) {
  let s = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first !== -1 && last > first) {
    s = s.substring(first, last + 1);
  }
  let result = '';
  let inStr = false;
  let esc = false;
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (esc) { result += c; esc = false; continue; }
    if (c === '\\' && inStr) { result += c; esc = true; continue; }
    if (c === '"') { inStr = !inStr; result += c; continue; }
    if (inStr) {
      if (c === '\n' || c === '\r') { result += ' '; continue; }
      if (c === '\t') { result += ' '; continue; }
      if (c.charCodeAt(0) < 0x20) { continue; }
    }
    result += c;
  }
  result = result.replace(/,(\s*[}\]])/g, '$1');
  return result;
}

let cleanText = cleanGeminiJson(text);
let data;

try {
  data = JSON.parse(cleanText);
} catch (e1) {
  try {
    let fixed = cleanText
      .replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"')
      .replace(/[\u2018\u2019\u201A\u201B\u2032\u2035]/g, "'")
      .replace(/^\uFEFF/, '');
    data = JSON.parse(fixed);
  } catch (e2) {
    const posMatch = e1.message.match(/position (\d+)/);
    const pos = posMatch ? parseInt(posMatch[1]) : 0;
    const start = Math.max(0, pos - 80);
    const end = Math.min(cleanText.length, pos + 80);
    const around = cleanText.substring(start, end);
    throw new Error(
      `JSON 파싱 실패: ${e1.message}\n` +
      `--- 에러 위치(${pos}) 주변 ---\n${around}\n` +
      `처음 300자: ${cleanText.substring(0, 300)}`
    );
  }
}

// images + subtitles 검증
if (!data.images || data.images.length < 4) {
  throw new Error('images must have at least 4 items, got: ' + (data.images?.length || 0));
}
if (!data.subtitles || data.subtitles.length < 6) {
  throw new Error('subtitles must have at least 6 items, got: ' + (data.subtitles?.length || 0));
}

const VALID_MOODS = ['thinking', 'excited', 'shocked', 'sad', 'angry', 'cool', 'celebrating'];

data.images = data.images.map((img, idx) => {
  if (!img.visual_type || !['image', 'meme'].includes(img.visual_type)) {
    img.visual_type = 'image';
  }
  if (img.visual_type === 'meme') {
    if (!img.meme_mood || !VALID_MOODS.includes(img.meme_mood)) {
      img.meme_mood = VALID_MOODS[idx % VALID_MOODS.length];
    }
  } else {
    img.meme_mood = '';
    if (!img.keyword) {
      img.keyword = 'abstract background';
    }
  }
  return img;
});

const fullDialogue = data.subtitles.join(' ');
const memeCount = data.images.filter(i => i.visual_type === 'meme').length;
const imageCount = data.images.filter(i => i.visual_type === 'image').length;

return [{
  json: {
    hook_title: data.hook_title,
    images: data.images,
    subtitles: data.subtitles,
    Subject: data.Subject,
    Caption: data.Caption,
    Comment: data.Comment,
    fullDialogue,
    imageCount: data.images.length,
    subtitleCount: data.subtitles.length,
    memeCount,
    Status: '생성 중',
    generatedAt: new Date().toISOString(),
    row_number: $('주제 파싱').first().json.row_number
  }
}];

const data = $('콘텐츠 파싱').first().json;
const images = data.images || [];

// images 배열만 세그먼트로 분리 (이미지 검색용)
return images.map((img, i) => ({
  json: {
    index: i,
    keyword: img.keyword || 'abstract background',
    visual_type: img.visual_type || 'image',
    meme_mood: img.meme_mood || '',
  }
}));

const items = $input.all();

return items.map(item => {
  const audioUrl = item.json.audio_url;
  const durationSec = item.json.duration_sec;

  if (!audioUrl) {
    throw new Error('TTS 응답에 audio_url이 없습니다: ' + JSON.stringify(item.json));
  }

  return {
    json: {
      audio_url: audioUrl,
      duration_sec: durationSec,
      ...item.json
    }
  };
});

// NCA v8: images + subtitles 분리 구조
const hookTitle = $('콘텐츠 파싱').first().json.hook_title;
const hookClean = hookTitle.replace(/<[^>]*>?/gm, '');
const subtitles = $('콘텐츠 파싱').first().json.subtitles || [];
const imageCount = $('콘텐츠 파싱').first().json.imageCount;

const ttsResult = $('TTS 결과 처리').first().json;
const mainAudioUrl = ttsResult.audio_url;
const audioDuration = ttsResult.duration_sec;
const totalDuration = audioDuration + 0.5;

const BGM_URL = 'http://76.13.182.180:9000/audio/bgm_25sec.mp3';
const SFX_MAP = {
  whoosh: 'http://76.13.182.180:9000/audio/sfx_whoosh1.mp3',
  pop: 'http://76.13.182.180:9000/audio/sfx_pop_user.mp3',
  ding: 'http://76.13.182.180:9000/audio/sfx_ding1.mp3',
  ding2: 'http://76.13.182.180:9000/audio/sfx_ding2.mp3',
  ppook: 'http://76.13.182.180:9000/audio/sfx_ppook.wav',
  wow: 'http://76.13.182.180:9000/audio/sfx_wow.wav'
};

function escapeDrawtext(text) {
  if (!text) return '';
  // 이모지 제거 (NanumGothicBold에 이모지 글리프 없음)
  text = text.replace(/[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F1E0}-\u{1F1FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}\u{FE00}-\u{FE0F}\u{1F900}-\u{1F9FF}\u{1FA00}-\u{1FA6F}\u{1FA70}-\u{1FAFF}\u{200D}\u{20E3}\u{FE0F}]/gu, '').trim();
  return text.replace(/\\/g, '\\\\').replace(/'/g, '\u2019').replace(/"/g, '\u201D').replace(/:/g, '\\:').replace(/;/g, '\\;').replace(/,/g, '\\,').replace(/\[/g, '\\[').replace(/\]/g, '\\]').replace(/\n/g, ' ');
}
function wrapSubtitle(text, maxLen) {
  if (!text) return '';
  const words = text.split(' ');
  let lines = [];
  let currentLine = '';
  for (const word of words) {
    if (currentLine.length + word.length > maxLen && currentLine.length > 0) {
      lines.push(currentLine.trim());
      currentLine = word + ' ';
    } else {
      currentLine += word + ' ';
    }
  }
  if (currentLine) lines.push(currentLine.trim());
  return lines.join('\n');
}

// === 이미지: audioDuration / imageCount 균등 배분 ===
const imgResults = $('이미지 URL 추출').all();
const imgDuration = audioDuration / imageCount;
let imgSegments = [];
for (let i = 0; i < imageCount; i++) {
  const imgData = imgResults[i]?.json || {};
  const imageUrl = imgData.images?.[0]?.url || '';
  const isVideo = imgData.is_video || false;
  const visualType = imgData.visual_type || 'image';
  if (!imageUrl) throw new Error(`이미지 ${i+1} URL 없음`);
  imgSegments.push({
    index: i,
    imageUrl,
    isVideo,
    visualType,
    start: i * imgDuration,
    duration: imgDuration
  });
}

// === 자막: 글자 수 비율로 시간 배분 (이미지와 독립) ===
const totalChars = subtitles.reduce((sum, s) => {
  return sum + s.replace(/<[^>]*>?/gm, '').replace(/\s+/g, '').length;
}, 0);

let subSegments = [];
let subStart = 0;
for (let i = 0; i < subtitles.length; i++) {
  const raw = subtitles[i];
  const clean = raw.replace(/<[^>]*>?/gm, '');
  const chars = clean.replace(/\s+/g, '').length;
  const ratio = totalChars > 0 ? chars / totalChars : 1 / subtitles.length;
  const dur = ratio * audioDuration;
  subSegments.push({
    index: i,
    raw,
    clean,
    start: subStart,
    duration: dur,
    hasEm: raw.includes('<em>')
  });
  subStart += dur;
}

// === FFmpeg inputs ===
let inputs = [];
let inputIndex = 0;
const mediaInputs = [];

// 1) 이미지/영상 (4~6개)
for (const img of imgSegments) {
  if (img.isVideo) {
    inputs.push({ file_url: img.imageUrl, options: [{ option: "-stream_loop", argument: "-1" }] });
  } else {
    inputs.push({ file_url: img.imageUrl, options: [{ option: "-loop", argument: "1" }, { option: "-framerate", argument: "30" }, { option: "-t", argument: img.duration.toFixed(2) }] });
  }
  mediaInputs.push({ idx: inputIndex, isVideo: img.isVideo, duration: img.duration });
  inputIndex++;
}

// 2) 통합 TTS
const audioIdx = inputIndex;
inputs.push({ file_url: mainAudioUrl, options: [] });
inputIndex++;

// 3) BGM
const bgmIdx = inputIndex;
inputs.push({ file_url: BGM_URL, options: [{ option: "-stream_loop", argument: "-1" }] });
inputIndex++;

// 4) SFX: 이미지 전환 + 강조 em
const sfxInputs = [];
for (let i = 0; i < imgSegments.length - 1; i++) {
  const next = imgSegments[i + 1];
  let sfxType = 'whoosh';
  if (next.visualType === 'meme') sfxType = 'ppook';
  inputs.push({ file_url: SFX_MAP[sfxType], options: [] });
  sfxInputs.push({ idx: inputIndex, type: sfxType, timeMs: Math.round(next.start * 1000) });
  inputIndex++;
}
for (const sub of subSegments) {
  if (sub.hasEm) {
    const emSfx = /\d/.test(sub.raw) ? 'ding2' : 'pop';
    inputs.push({ file_url: SFX_MAP[emSfx], options: [] });
    sfxInputs.push({ idx: inputIndex, type: emSfx, timeMs: Math.round((sub.start + 0.3) * 1000) });
    inputIndex++;
  }
}

// === FILTER COMPLEX ===
let filterParts = [];

// 비디오 스케일 + concat
for (let i = 0; i < imgSegments.length; i++) {
  const m = mediaInputs[i];
  if (m.isVideo) {
    filterParts.push(`[${m.idx}:v]trim=duration=${m.duration.toFixed(2)},setpts=PTS-STARTPTS,scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black,setsar=1,fps=30[v${i}]`);
  } else {
    filterParts.push(`[${m.idx}:v]scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black,setsar=1,fps=30[v${i}]`);
  }
}
const vLabels = imgSegments.map((_, i) => `[v${i}]`).join('');
filterParts.push(`${vLabels}concat=n=${imgSegments.length}:v=1:a=0[vconcat]`);

// 오디오
filterParts.push(`[${audioIdx}:a]atrim=duration=${audioDuration},asetpts=PTS-STARTPTS[tts_raw]`);
filterParts.push(`[${bgmIdx}:a]atrim=duration=${totalDuration},asetpts=PTS-STARTPTS,volume=0.12,afade=t=out:st=${Math.max(0, totalDuration - 2)}:d=2[bgm]`);

// SFX mix
const sfxCount = sfxInputs.length;
if (sfxCount > 0) {
  for (let i = 0; i < sfxCount; i++) {
    const si = sfxInputs[i];
    filterParts.push(`[${si.idx}:a]atrim=duration=0.3,asetpts=PTS-STARTPTS,volume=0.15,adelay=${si.timeMs}|${si.timeMs}[sfx${i}]`);
  }
  const sfxMixLabels = sfxInputs.map((_, i) => `[sfx${i}]`).join('');
  filterParts.push(`${sfxMixLabels}amix=inputs=${sfxCount}:duration=longest:normalize=0[sfx_mix]`);
  filterParts.push(`[tts_raw][bgm][sfx_mix]amix=inputs=3:duration=longest:weights=1 0.12 0.4:normalize=0[afinal]`);
} else {
  filterParts.push(`[tts_raw][bgm]amix=inputs=2:duration=longest:weights=1 0.12:normalize=0[afinal]`);
}

// 자막 오버레이 (상단 제목 + 하단 자막 + 훅)
let overlayFilter = `[vconcat]drawbox=y=40:w=1080:h=280:color=#000000@1.0:t=fill,drawtext=expansion=none:text='${escapeDrawtext(hookClean)}':fontsize=72:fontcolor=white:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=120:line_spacing=12`;

// 자막 (글자수 비율 기반 타이밍, 이미지 전환과 독립)
for (const sub of subSegments) {
  const subText = escapeDrawtext(wrapSubtitle(sub.clean, 12));
  const startT = sub.start.toFixed(2);
  const endT = (sub.start + sub.duration).toFixed(2);
  overlayFilter += `,drawtext=expansion=none:text='${subText}':fontsize=52:fontcolor=white:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=h-280:borderw=4:bordercolor=black:enable='between(t,${startT},${endT})'`;
}

// 훅 자막
const hookEscaped = escapeDrawtext(wrapSubtitle(hookClean, 13));
const hookEndT = 2.5;
overlayFilter += `,drawbox=y=(h-300)/2:w=1080:h=300:color=#000000@0.7:t=fill:enable='between(t,0,${hookEndT})'`;
overlayFilter += `,drawtext=expansion=none:text='${hookEscaped}':fontsize=80:fontcolor=#CCFF00:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=(h-th)/2:borderw=4:bordercolor=black:enable='between(t,0,${hookEndT})'`;
overlayFilter += '[vfinal]';
filterParts.push(overlayFilter);

const nca_payload = {
  inputs,
  filters: [{ filter: filterParts.join(';') }],
  outputs: [{
    options: [
      { option: "-map", argument: "[vfinal]" }, { option: "-map", argument: "[afinal]" },
      { option: "-c:v", argument: "libx264" }, { option: "-preset", argument: "fast" }, { option: "-crf", argument: "23" },
      { option: "-c:a", argument: "aac" }, { option: "-b:a", argument: "192k" },
      { option: "-pix_fmt", argument: "yuv420p" }, { option: "-movflags", argument: "+faststart" }, { option: "-t", argument: totalDuration.toFixed(2) }
    ],
    file_name: "kkultip_shorts_final.mp4"
  }]
};

return [{
  json: {
    nca_payload,
    totalDuration,
    imageCount: imgSegments.length,
    subtitleCount: subSegments.length,
    hookTitle,
    subject: $('콘텐츠 파싱').first().json.Subject,
    caption: $('콘텐츠 파싱').first().json.Caption,
    comment: $('콘텐츠 파싱').first().json.Comment
  }
}];

// NCA 결과 처리
const result = $input.first().json;
const prevData = $('NCA 데이터 준비').first().json;

let videoUrl = '';
if (Array.isArray(result.response)) {
  videoUrl = result.response[0]?.file_url || '';
} else if (typeof result.response === 'string') {
  videoUrl = result.response;
} else {
  videoUrl = result.output_url || result.url || result.video_url || result.file_url || '';
}

if (!videoUrl) {
  throw new Error('NCA 영상 제작 결과 URL 없음: ' + JSON.stringify(result).substring(0, 500));
}

return [{
  json: {
    '영상 URL': videoUrl,
    final_video_url: videoUrl,
    url: videoUrl,
    subject: prevData.subject,
    caption: prevData.caption,
    comment: prevData.comment,
    topic: $('주제 파싱').first().json.topic,
  }
}];

// 밈 카탈로그: MinIO에 호스팅된 밈/리액션 영상 URL (35개)
const MEME_CATALOG = {
  thinking: [
    'http://76.13.182.180:9000/memes/thinking/meme_thinking_01.mp4',
    'http://76.13.182.180:9000/memes/thinking/meme_thinking_02.mp4',
    'http://76.13.182.180:9000/memes/thinking/meme_thinking_03.mp4',
    'http://76.13.182.180:9000/memes/thinking/meme_thinking_04.mp4',
    'http://76.13.182.180:9000/memes/thinking/meme_thinking_05.mp4',
  ],
  excited: [
    'http://76.13.182.180:9000/memes/excited/meme_excited_01.mp4',
    'http://76.13.182.180:9000/memes/excited/meme_excited_02.mp4',
    'http://76.13.182.180:9000/memes/excited/meme_excited_03.mp4',
    'http://76.13.182.180:9000/memes/excited/meme_excited_04.mp4',
    'http://76.13.182.180:9000/memes/excited/meme_excited_05.mp4',
  ],
  shocked: [
    'http://76.13.182.180:9000/memes/shocked/meme_shocked_01.mp4',
    'http://76.13.182.180:9000/memes/shocked/meme_shocked_02.mp4',
    'http://76.13.182.180:9000/memes/shocked/meme_shocked_03.mp4',
    'http://76.13.182.180:9000/memes/shocked/meme_shocked_04.mp4',
    'http://76.13.182.180:9000/memes/shocked/meme_shocked_05.mp4',
  ],
  sad: [
    'http://76.13.182.180:9000/memes/sad/meme_sad_01.mp4',
    'http://76.13.182.180:9000/memes/sad/meme_sad_02.mp4',
    'http://76.13.182.180:9000/memes/sad/meme_sad_03.mp4',
    'http://76.13.182.180:9000/memes/sad/meme_sad_04.mp4',
    'http://76.13.182.180:9000/memes/sad/meme_sad_05.mp4',
  ],
  angry: [
    'http://76.13.182.180:9000/memes/angry/meme_angry_01.mp4',
    'http://76.13.182.180:9000/memes/angry/meme_angry_02.mp4',
    'http://76.13.182.180:9000/memes/angry/meme_angry_03.mp4',
    'http://76.13.182.180:9000/memes/angry/meme_angry_04.mp4',
    'http://76.13.182.180:9000/memes/angry/meme_angry_05.mp4',
  ],
  cool: [
    'http://76.13.182.180:9000/memes/cool/meme_cool_01.mp4',
    'http://76.13.182.180:9000/memes/cool/meme_cool_02.mp4',
    'http://76.13.182.180:9000/memes/cool/meme_cool_03.mp4',
    'http://76.13.182.180:9000/memes/cool/meme_cool_04.mp4',
    'http://76.13.182.180:9000/memes/cool/meme_cool_05.mp4',
  ],
  celebrating: [
    'http://76.13.182.180:9000/memes/celebrating/meme_celebrating_01.mp4',
    'http://76.13.182.180:9000/memes/celebrating/meme_celebrating_02.mp4',
    'http://76.13.182.180:9000/memes/celebrating/meme_celebrating_03.mp4',
    'http://76.13.182.180:9000/memes/celebrating/meme_celebrating_04.mp4',
    'http://76.13.182.180:9000/memes/celebrating/meme_celebrating_05.mp4',
  ],
};

const items = $input.all();
const segAll = $('세그먼트 분리').all();

return items.map((item, i) => {
  const data = item.json;
  const segData = segAll[i]?.json || {};
  const visualType = segData.visual_type || 'image';
  const memeMood = segData.meme_mood || 'thinking';

  if (visualType === 'meme') {
    const catalog = MEME_CATALOG[memeMood] || MEME_CATALOG.thinking;
    const randomIdx = Math.floor(Math.random() * catalog.length);
    return {
      json: {
        ...data,
        visual_type: 'meme',
        meme_mood: memeMood,
        images: [{ url: catalog[randomIdx] }],
        is_video: true,
      }
    };
  } else {
    const photos = data.photos || [];
    let imageUrl = '';
    if (photos.length > 0) {
      const randPhoto = photos[Math.floor(Math.random() * photos.length)];
      imageUrl = randPhoto.src?.portrait || randPhoto.src?.large || randPhoto.src?.medium || '';
    }
    if (!imageUrl) {
      imageUrl = 'https://images.pexels.com/photos/1229861/pexels-photo-1229861.jpeg?auto=compress&cs=tinysrgb&w=1080';
    }
    return {
      json: {
        ...data,
        visual_type: 'image',
        meme_mood: '',
        images: [{ url: imageUrl }],
        is_video: false,
      }
    };
  }
});

const raw = $input.first().json;
let text = '';
if (raw.content && raw.content.parts) {
  text = raw.content.parts[0].text;
} else if (typeof raw === 'string') {
  text = raw;
} else if (raw.text) {
  text = raw.text;
} else {
  text = JSON.stringify(raw);
}

const cleanText = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const data = JSON.parse(cleanText);

if (!data.topic) {
  throw new Error('AI 주제 생성 결과에 topic이 없습니다: ' + cleanText);
}

return [{
  json: {
    topic: data.topic,
    row_number: null
  }
}];
